from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismBuildEntityNode(BaseNode):
    name = "Prism: Build Entity Dict"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("entity_type", "string", widget_type="dropdown", options=["asset","shot"], default="asset")
        self.add_input("asset_path", "string", widget_type="text", default="chars/dog")
        self.add_input("sequence", "string", widget_type="text", default="a")
        self.add_input("shot", "string", widget_type="text", default="0010")
        self.add_output("entity", "dict")

    def _compute(self):
        etype = self.get_parameter('entity_type') or 'asset'
        if etype == 'asset':
            return {'type':'asset', 'asset_path': self.get_parameter('asset_path') or ''}
        return {'type':'shot', 'sequence': self.get_parameter('sequence') or '', 'shot': self.get_parameter('shot') or ''}

    async def on_parameter_changed(self, name, value):
        if name in ('entity_type','asset_path','sequence','shot'):
            self.parameters['entity'] = self._compute()

    async def execute(self, inputs):
        etype = inputs.get('entity_type') or 'asset'
        if etype == 'asset':
            ent = {'type':'asset','asset_path': inputs.get('asset_path') or ''}
        else:
            ent = {'type':'shot','sequence': inputs.get('sequence') or '', 'shot': inputs.get('shot') or ''}
        return {'entity': ent}

def register_node():
    return PrismBuildEntityNode
